############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("Form")->variables->are(c => "Real"); $ans1 = Formula("13c"); Context("Form")->variables->are(q => "Real"); $ans2 = Formula("-8q^2"); Context("Form")->variables->add(y => "Real"); $ans3 = Formula("5x-5y"); Context("Form")->variables->add(y => "Real", z => "Real"); $ans4 = Formula("2x-3y+4z");
